 1	import * as React from 'react';
 2	import { Button, Popover, PopoverPosition } from '@patternfly/react-core';
 3	import PipelineResourceStatus from './PipelineResourceStatus';
 4	import PipelineRunStatusPopoverContent from './PipelineRunStatusPopoverContent';
 5	import { ComputedStatus, PipelineRunKind } from '../../types';
 6	
 7	import './PipelineRunStatusContent.scss';
 8	
 9	type PipelineRunStatusProps = {
10	  status: string;
11	  pipelineRun: PipelineRunKind;
12	  title?: string;
13	};
14	const PipelineRunStatusContent: React.FC<PipelineRunStatusProps> = ({
15	  status,
16	  pipelineRun,
17	  title,
18	}) => {
19	  const [isPopoverOpen, setIsPopoverOpen] = React.useState(false);
20	
21	  const PopoverContent = () => {
22	    return (
23	      <>
24	        {isPopoverOpen && (
25	          <PipelineRunStatusPopoverContent pipelineRun={pipelineRun} />
26	        )}
27	      </>
28	    );
29	  };
30	  return (
31	    <>
32	      {pipelineRun ? (
33	        status === ComputedStatus.Failed ? (
34	          <Popover
35	            bodyContent={PopoverContent}
36	            isVisible={isPopoverOpen}
37	            shouldClose={() => setIsPopoverOpen(false)}
38	            shouldOpen={() => setIsPopoverOpen(true)}
39	            position={PopoverPosition.auto}
40	          >
41	            <Button variant="plain" className="odc-status-column-text">
42	              <PipelineResourceStatus status={status} title={title} />
43	            </Button>
44	          </Popover>
45	        ) : (
46	          <PipelineResourceStatus status={status} title={title} />
47	        )
48	      ) : (
49	        <>{'-'}</>
50	      )}
51	    </>
52	  );
53	};
54	
55	export default PipelineRunStatusContent;

